import { useCallback, useReducer } from 'react';

import useCancellablePromise from 'Shared/hooks/useCancellablePromise';

const REQUEST_DATA = 'request_data';
const REQUEST_DATA_SUCCESS = 'request_data_success';
const REQUEST_DATA_FAILURE = 'request_data_failure';
const RESET = 'reset';

type State<T> = {
  data: T | null;
  error: unknown;
  loading: boolean;
};

type Action<T> =
  | { type: typeof REQUEST_DATA }
  | { type: typeof REQUEST_DATA_SUCCESS; payload: T }
  | { type: typeof REQUEST_DATA_FAILURE; payload: unknown }
  | { type: typeof RESET };

const INITIAL_RESPONSE_STATE: State<unknown> = {
  data: null,
  error: null,
  loading: false,
};

function reducer<T>(state: State<T>, action: Action<T>): State<T> {
  switch (action.type) {
    case REQUEST_DATA:
      return { ...state, loading: true };

    case REQUEST_DATA_SUCCESS:
      return { ...state, data: action.payload, loading: false };

    case REQUEST_DATA_FAILURE:
      return { data: null, error: action.payload, loading: false };

    case RESET:
      return { ...INITIAL_RESPONSE_STATE } as State<T>;

    default:
      throw new Error('Unknown action');
  }
}

function useAsyncFn<P extends unknown[], T>(
  fn: (...args: P) => T | Promise<T>,
) {
  const [response, dispatch] = useReducer(
    reducer<T>,
    INITIAL_RESPONSE_STATE as State<T>,
  );
  const { makeCancellable } = useCancellablePromise();

  const callAsyncFn = useCallback(
    async (...props: P) => {
      try {
        dispatch({ type: REQUEST_DATA });

        const result = fn(...props);
        const data = await makeCancellable(Promise.resolve(result));

        dispatch({ type: REQUEST_DATA_SUCCESS, payload: data });
      } catch (error) {
        dispatch({ type: REQUEST_DATA_FAILURE, payload: error });
      }
    },
    [fn, makeCancellable],
  );

  const resetResponse = useCallback(() => dispatch({ type: RESET }), []);

  return {
    callAsyncFn,
    resetResponse,
    response,
  };
}

