import React, { useEffect } from 'react';
import { useRouteError, isRouteErrorResponse } from 'react-router-dom';
import * as Sentry from '@sentry/react';

import MainLayout from 'Components/layouts/main/MainLayout';

import ErrorInfo from './ErrorInfo';

export const GlobalErrorBoundary = () => {
  const error = useRouteError();

  useEffect(() => {
    if (error) {
      Sentry.captureException(error);
    }
  }, [error]);

  if (isRouteErrorResponse(error)) {
    return (
      <MainLayout className="error-page">
        <h1>{error.status}</h1>
        <p>{error.statusText || 'Something went wrong'}</p>
      </MainLayout>
    );
  }

  return <ErrorInfo error={error} />;
};

import React from 'react';
import axios from 'axios';
import { IoWarningOutline } from 'react-icons/io5';

import './errorInfo.scss';

import MainLayout from 'Components/layouts/main/MainLayout';
import { formatRequestBodyReadableString } from 'Shared/utils/objectHelper';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';

type PropsT = {
  error: unknown;
  resetError?: () => void;
};

const ErrorInfo = ({ error, resetError }: PropsT) => {
  return (
    <MainLayout className="error-page">
      <div className="error-page__container">
        <div className="error-page__icon-wrapper">
          <IoWarningOutline className="error-page__icon" />
        </div>

        <h1>Error Occurred</h1>

        {axios.isAxiosError(error) ? (
          <>
            <p className="error-page__description">
              Failed to connect to server. Please check your internet connection
              and try again.
            </p>

            {error.response && (
              <p className="error-page__code">
                Error code: {error.response.status || 'Network Error'} -{' '}
                {error.response.statusText || error.code || ''}
              </p>
            )}
          </>
        ) : (
          <>
            <p className="error-page__description">
              An unexpected error occurred. Please try again later.
            </p>
          </>
        )}

        {resetError && (
          <div className="error-page__actions">
            <AuButton
              kind={AuButtonKindE.PRIMARY}
              onClick={resetError}
              className="error-page__button"
            >
              Try Again
            </AuButton>
          </div>
        )}
      </div>

      {process.env.NODE_ENV === 'development' && (
        <div className="error-page__dev-container">
          <p>
            <strong>Error:</strong>{' '}
            {error instanceof Error ? error.name : 'Unknown Error'}
          </p>
          <p>
            <strong>Message:</strong>{' '}
            {error instanceof Error ? error.message : String(error)}
          </p>

          {axios.isAxiosError(error) && (
            <div className="axios-details">
              <p>
                <strong>Status:</strong> {error.response?.status ?? 'Unknown'}
              </p>
              <p>
                <strong>Method:</strong> {error.config?.method?.toUpperCase()}
              </p>
              <p>
                <strong>URL:</strong> {error.config?.url}
              </p>

              {error.config?.params &&
                Object.keys(error.config.params).length > 0 && (
                  <details className="details-block">
                    <summary>
                      <strong>Request Query Params</strong>
                    </summary>
                    <pre>{JSON.stringify(error.config.params, null, 2)}</pre>
                  </details>
                )}

              {error.config?.data && (
                <details className="details-block">
                  <summary>
                    <strong>Request Body (Payload)</strong>
                  </summary>
                  <pre>
                    {formatRequestBodyReadableString(error.config.data)}
                  </pre>
                </details>
              )}

              {error.response?.data &&
              typeof error.response.data === 'object' ? (
                <details
                  open
                  className="details-block"
                >
                  <summary>
                    <strong>Response Data</strong>
                  </summary>
                  <pre>{JSON.stringify(error.response.data, null, 2)}</pre>
                </details>
              ) : (
                <p>
                  <em>Server returned non-JSON response</em>
                </p>
              )}
            </div>
          )}

          {error instanceof Error && (
            <details className="details-block stack-trace">
              <summary>Stack Trace</summary>
              <pre className="stack-pre">{error.stack}</pre>
            </details>
          )}
        </div>
      )}
    </MainLayout>
  );
};

export default ErrorInfo;

