import React from 'react';

import './deleteAccountSidebar.scss';

import Sidebar from 'Components/sidebar/Sidebar';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import { SidebarSizeE } from 'Components/sidebar/types/SidebarSizeE';
import { useSidebarProps } from 'Components/sidebar/useSidebarProps';
import TrashSvg from 'Components/svg/TrashSvg';
import { sidebarService } from 'Services/sidebarService';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import { useDeleteBankAccount } from 'Repositories/bankAccounts/useDeleteBankAccount';
import { notificationService } from 'Services/notificationService';

const DeleteBankAccountSidebar = () => {
  const { accountId } = useSidebarProps(SidebarNameE.ACCOUNT_DELETE);

  const deleteAccount = useDeleteBankAccount();

  const handleDelete = async () => {
    if (!accountId) return;

    try {
      await deleteAccount([accountId]);

      sidebarService.closeAll();
    } catch (error: unknown) {
      notificationService.addAlert(
        (error as Error).message || 'Failed to delete this account.',
      );
    }
  };

  return (
    <Sidebar
      name={SidebarNameE.ACCOUNT_DELETE}
      size={SidebarSizeE.SMALL}
    >
      <div className="delete-account-sidebar">
        <h2 className="delete-account-sidebar__title">
          Do you really want to delete this account?
        </h2>

        <p className="delete-account-sidebar__subtitle">
          This action can&apos;t be undone.
        </p>

        <div className="delete-account-sidebar__actions">
          <AuButton
            kind={AuButtonKindE.PRIMARY}
            size={AuButtonSizeE.LARGE}
            onClick={() => {
              sidebarService.close(SidebarNameE.ACCOUNT_DELETE);
            }}
          >
            Go back
          </AuButton>

          <AuButton
            kind={AuButtonKindE.SECONDARY}
            size={AuButtonSizeE.LARGE}
            className="delete-account-sidebar__danger"
            onClick={handleDelete}
          >
            <span className="delete-account-sidebar__danger-icon">
              <TrashSvg />
            </span>
            <span>Delete anyway</span>
          </AuButton>
        </div>
      </div>
    </Sidebar>
  );
};

export default DeleteBankAccountSidebar;

