    10→const SECONDS_TO_THINK = 5;
    11→
    12→type DeleteFunctionT = (ids: UuidT[]) => Promise<void>;
    13→
    14→export const useSaveRemoval = (
    15→  idsListKey: IdsListKeyE,
    16→  onDeleteItems: DeleteFunctionT,
    17→): DeleteFunctionT => {
    18→  const { onAddIds, onRemoveIds } = useIdsList(idsListKey);
    19→
    20→  return useCallback(
    21→    async (itemsIds: UuidT[]) => {
    22→      onAddIds(itemsIds);
    23→
    24→      const alertId = notificationService.addAlert(
    25→        <SaveRemovalNotification
    26→          ids={itemsIds}
    27→          onDelete={async () => {
    28→            try {
    29→              await onDeleteItems(itemsIds);
    30→            } catch (err) {
    31→              throw err;
    32→            } finally {
    33→              onRemoveIds(itemsIds);
    34→
    35→              notificationService.removeAlert(alertId);
    36→            }
    37→          }}
    38→          onCancel={() => {
    39→            onRemoveIds(itemsIds);
    40→
    41→            notificationService.removeAlert(alertId);
    42→          }}
