import { useCallback } from 'react';

import { UuidT } from 'Shared/types/UuidT';
import { notificationService } from 'Services/notificationService';
import SaveRemovalNotification from 'Shared/hooks/saveRemovalNotification/SaveRemovalNotification';
import { MILLISECONDS_IN_SECOND } from 'Shared/constants/time';
import { IdsListKeyE } from 'Shared/types/IdsListKeyE';
import { useIdsList } from 'Shared/hooks/useIdsList';

const SECONDS_TO_THINK = 5;

type DeleteFunctionT = (ids: UuidT[]) => Promise<void>;

export const useSaveRemoval = (
  idsListKey: IdsListKeyE,
  onDeleteItems: DeleteFunctionT,
): DeleteFunctionT => {
  const { onAddIds, onRemoveIds } = useIdsList(idsListKey);

  return useCallback(
    async (itemsIds: UuidT[]) => {
      onAddIds(itemsIds);

      const alertId = notificationService.addAlert(
        <SaveRemovalNotification
          ids={itemsIds}
          onDelete={async () => {
            try {
              await onDeleteItems(itemsIds);
            } catch (err) {
              throw err;
            } finally {
              onRemoveIds(itemsIds);

              notificationService.removeAlert(alertId);
            }
          }}
          onCancel={() => {
            onRemoveIds(itemsIds);

            notificationService.removeAlert(alertId);
          }}
          secondsToThink={SECONDS_TO_THINK}
        />,
        SECONDS_TO_THINK * MILLISECONDS_IN_SECOND,
      );
    },
    [onAddIds, onDeleteItems, onRemoveIds],
  );
};

export enum FormValidationErrorTypeE {
  FIELD = 'field',
}
